INSERT INTO `professional_profiles` (`user_id`, `category`, `title`, `bio`, `curriculum`, `specializations`, `photo`, `partita_iva`, `codice_fiscale`, `regime_fiscale`, `cassa_previdenziale`, `albo_professionale`, `numero_albo`, `invoice_counter`, `is_bookable`, `session_duration_minutes`, `session_price`, `booking_notes`, `phone`, `website`, `created_at`, `updated_at`, `address`, `slug`, `is_founder`) VALUES (@sara, 'Psicologa', 'Dott.ssa', 'La Dott.ssa Alessandri lavora accanto a persone che stanno attraversando momenti di fragilità emotiva o legati alla malattia, offrendo uno spazio accogliente e protetto in cui sentirsi compresi e sostenuti. Il suo intervento si distingue per la capacità di integrare ascolto autentico e competenze cliniche, accompagnando la persona in un percorso concreto di maggiore consapevolezza e benessere. È una scelta indicata per chi desidera un supporto attento, rispettoso e profondamente umano.', '{"formazione":[{"titolo":"Laurea Magistrale in Psicologia Cognitiva Applicata","ente":"Alma Mater Studiorum – Università di Bologna","voto":"110\\/110 con lode","anno":"2025"},{"titolo":"Laurea Triennale in Scienze e Tecniche Psicologiche","ente":"Alma Mater Studiorum – Università di Bologna","anno":"2023"},{"titolo":"Scuola di Psicoterapia Biosistemica","nota":"In formazione dal 2026"},{"titolo":"Albo A – Ordine Psicologi Emilia-Romagna","nota":"n°12648, iscritta dal nov. 2025"}],"esperienze":[{"ruolo":"Tirocinio in Psicologia Oncologica","ente":"U.O. Psicologia Oncologica, Osp. Sant\'Orsola-Malpighi – Bologna","periodo":"Gen. 2026 – in corso","attivita":["Osservazione clinica dei colloqui di supporto a pazienti oncologici e caregiver","Apprendimento delle procedure di refertazione clinica","Partecipazione al progetto Hospice per pazienti in degenza"]},{"ruolo":"Tirocinio Pratico Valutativo – 500 ore","ente":"AUSL Bologna, Dip. Salute Mentale – Distretto Porto-Saragozza","periodo":"Mar. – Set. 2025","attivita":["Colloqui clinici e anamnestici per l\'inquadramento diagnostico dei pazienti","Valutazione dei Disturbi Emotivi Comuni (DEC) tramite test standardizzati","Partecipazione a riunioni d\'équipe multidisciplinari e discussione di casi clinici"]}],"aree":["Specializzanda in Psicoterapia Biosistemica","Psicologia oncologica","Supporto nei percorsi di malattia","Valutazione dei Disturbi Emotivi Comuni (DEC)","Difficoltà emotive e supporto psicologico"]}', NULL, NULL, '04567021021', 'LSSSRA00H56A944C', 'ordinario', 'ENPAP', 'Emilia Romagna', '12648', 2, 1, 50, '55.00', NULL, '3397430735', NULL, '2026-04-10 22:14:46', '2026-05-08 08:09:38', NULL, 'sara-alessandri', 1);

